# AUTOGENERATED! DO NOT EDIT!

def llm_filter_candidates(candidates, job_ads, ctx, print) -> {"weighted_codes": dict}:
    """Filter O*NET candidates using LLM negative selection and normalize weights."""
    from ai_index.utils import maybe_run_remote
    
    remote_result = maybe_run_remote(
        func_path="ai_index.nodes.llm_filter_candidates.llm_filter_candidates",
        inputs={"candidates": candidates, "job_ads": job_ads},
        ctx=ctx, print_fn=print,
        job_name="llm_filter_candidates", time="02:00:00",
        required_models_from_vars=["llm_model"],
    )
    if remote_result is not None:
        return remote_result
    import json
    import re
    
    execution_mode = ctx.vars.get("execution_mode", "local")
    
    llm_model = ctx.vars.get("llm_model", "meta-llama/Meta-Llama-3.1-8B-Instruct")
    llm_dtype = ctx.vars.get("llm_dtype", "float16")
    llm_batch_size = ctx.vars.get("llm_batch_size", 128)
    max_new_tokens = ctx.vars.get("llm_max_new_tokens", 60)
    max_keep = ctx.vars.get("llm_max_keep", 5)
    
    # Build lookup from job_ads for fast access
    ad_lookup = {}
    ad_job_ids = job_ads["job_ids"]
    ad_short_desc = job_ads.get("short_desc", [""] * len(ad_job_ids))
    ad_tasks_skills = job_ads.get("tasks_and_skills", [""] * len(ad_job_ids))
    ad_domains = job_ads.get("domains", [""] * len(ad_job_ids))
    for idx in range(len(ad_job_ids)):
        ad_lookup[ad_job_ids[idx]] = {
            "short_desc": str(ad_short_desc[idx] or ""),
            "tasks_and_skills": str(ad_tasks_skills[idx] or ""),
            "domains": str(ad_domains[idx] or ""),
        }
    
    cand_job_ids = candidates["job_ids"]
    cand_lists = candidates["candidates"]
    n_jobs = len(cand_job_ids)
    print(f"llm_filter_candidates: {n_jobs} jobs, model={llm_model}, mode={execution_mode}, batch_size={llm_batch_size}, max_keep={max_keep}")
    MAX_INPUT_TOKENS = 200  # chars of job text to include
    
    def _build_prompt(short_desc, tasks_and_skills, domains, titles, max_keep):
        """Build the negative-selection prompt for a single job ad."""
        numbered = "\n".join(f"{i+1}. {t}" for i, t in enumerate(titles))
        return f"""Analyze job-to-title matching.
    
    Job Description: {short_desc[:MAX_INPUT_TOKENS]}
    Skills/Tasks: {tasks_and_skills[:MAX_INPUT_TOKENS]}
    Sector: {domains}
    
    Candidate O*NET Titles:
    {numbered}
    
    Return JSON object with "drop" key. Value is array of numbers for irrelevant titles, or null if all match.
    IMPORTANT: Keep at least one title - never drop all titles.
    Be conservative - only drop titles that clearly don't fit.
    JSON response:""".strip()
    
    
    def _parse_drop_response(reply, n_titles):
        """Parse LLM response to extract drop indices (1-based)."""
        # Try to find a JSON object in the reply
        m = re.search(r"\{[^}]*\}", reply, flags=re.S)
        if not m:
            return []  # parse failure -> keep all
        try:
            obj = json.loads(m.group(0))
        except json.JSONDecodeError:
            return []
        drop = obj.get("drop")
        if drop is None or not isinstance(drop, list):
            return []
        # Validate: must be integers in [1, n_titles]
        valid = [int(d) for d in drop if isinstance(d, (int, float)) and 1 <= int(d) <= n_titles]
        return valid
    
    
    def _apply_filter_and_normalize(titles, scores, reply, max_keep):
        """Apply drop filter from LLM reply and normalize to sum-to-1 weights."""
        n_titles = len(titles)
        drop_ids = _parse_drop_response(reply, n_titles)
    
        # Safety: if all dropped, keep first candidate
        if len(drop_ids) >= n_titles:
            drop_ids = drop_ids[:n_titles - 1]
    
        # Filter and cap at max_keep
        drop_set = set(drop_ids)
        filtered = [(t, s) for j, (t, s) in enumerate(zip(titles, scores)) if (j + 1) not in drop_set]
        filtered = filtered[:max_keep]
    
        # Normalize to sum-to-1 weights
        total = sum(s for _, s in filtered)
        return {t: s / total if total > 0 else 0.0 for t, s in filtered}
    def _run_api_mode(cand_job_ids, cand_lists, ad_lookup, llm_model,
                      max_new_tokens, max_keep, llm_batch_size, print_fn):
        """Run LLM filtering via adulib API (for api execution mode)."""
        import asyncio
        import adulib.llm as adulib_llm
        from adulib.asynchronous import batch_executor
    
        n_jobs = len(cand_job_ids)
    
        # Build all prompts and track which jobs need LLM calls
        job_prompts = []  # (index_in_all_weighted, prompt, titles, scores)
        all_weighted = [None] * n_jobs
    
        for i, (jid, cands) in enumerate(zip(cand_job_ids, cand_lists)):
            titles = [t for t, s in cands]
            scores = [s for t, s in cands]
            ad = ad_lookup.get(jid)
            if ad is None:
                total = sum(scores[:max_keep])
                all_weighted[i] = {t: s / total if total > 0 else 0.0 for t, s in cands[:max_keep]}
                continue
            prompt = _build_prompt(ad["short_desc"], ad["tasks_and_skills"], ad["domains"], titles, max_keep)
            job_prompts.append((i, prompt, titles, scores))
    
        if not job_prompts:
            return all_weighted
    
        # Define async worker for batch_executor
        system_msg = "You are a job classification assistant. Respond only with valid JSON."
    
        async def _call_llm(item):
            idx, prompt, titles, scores = item
            response, _cache_hit, _call_log = await adulib_llm.async_single(
                model=llm_model,
                system=system_msg,
                prompt=prompt,
                max_tokens=max_new_tokens,
            )
            return idx, _apply_filter_and_normalize(titles, scores, response, max_keep)
    
        # Run with batch_executor for concurrency control
        async def _run_all():
            results = await batch_executor(
                _call_llm,
                job_prompts,
                max_concurrent=llm_batch_size,
            )
            return results
    
        print_fn(f"llm_filter_candidates (api): processing {len(job_prompts)} jobs with {llm_model}...")
        results = asyncio.run(_run_all())
    
        for idx, weights in results:
            all_weighted[idx] = weights
    
        return all_weighted
    if execution_mode == "api":
        all_weighted = _run_api_mode(
            cand_job_ids, cand_lists, ad_lookup, llm_model,
            max_new_tokens, max_keep, llm_batch_size, print,
        )
    else:
        from isambard_utils.models import load_llm
        llm = load_llm(llm_model, device="cuda", dtype=llm_dtype)
        print(f"llm_filter_candidates: model loaded")
    
        all_weighted = []
        n_batches = (n_jobs + llm_batch_size - 1) // llm_batch_size
    
        for batch_idx in range(n_batches):
            start = batch_idx * llm_batch_size
            end = min(start + llm_batch_size, n_jobs)
            batch_job_ids = cand_job_ids[start:end]
            batch_cands = cand_lists[start:end]
    
            # Build prompts
            prompts = []
            batch_titles = []  # parallel list of (titles, scores) per job in batch
            for jid, cands in zip(batch_job_ids, batch_cands):
                titles = [t for t, s in cands]
                scores = [s for t, s in cands]
                ad = ad_lookup.get(jid)
                if ad is None:
                    # Missing job ad — pass through cosine weights directly
                    total = sum(scores[:max_keep])
                    weights = {t: s / total if total > 0 else 0.0 for t, s in cands[:max_keep]}
                    all_weighted.append(weights)
                    prompts.append(None)
                    batch_titles.append(None)
                    continue
                prompt = _build_prompt(ad["short_desc"], ad["tasks_and_skills"], ad["domains"], titles, max_keep)
                prompts.append(prompt)
                batch_titles.append((titles, scores))
    
            # Filter out None prompts for actual LLM call
            real_prompts = [p for p in prompts if p is not None]
            real_indices = [i for i, p in enumerate(prompts) if p is not None]
    
            if real_prompts:
                replies = llm.generate(real_prompts, max_new_tokens=max_new_tokens)
    
                for local_idx, reply in zip(real_indices, replies):
                    titles, scores = batch_titles[local_idx]
                    weights = _apply_filter_and_normalize(titles, scores, reply, max_keep)
                    all_weighted.append(weights)
    
            if (batch_idx + 1) % 10 == 0 or end == n_jobs:
                print(f"  llm_filter: {end}/{n_jobs} jobs processed")
    
    print(f"llm_filter_candidates: done — {n_jobs} jobs")
    return {"weighted_codes": {
        "job_ids": cand_job_ids,
        "weights": all_weighted,
    }}
